import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Card, Button, Spinner, Alert } from 'react-bootstrap';
import api from '../services/api';
import '../styles/card.css';

const EventDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchEvent = async () => {
      console.log('Fetching event with id:', id);
      try {
        const response = await api.get(`/events/${id}`);
        console.log('API response:', response);
        setEvent(response.data);
      } catch (err) {
        console.error('Error fetching event:', err);
        setError('Không thể tải thông tin sự kiện. Vui lòng thử lại.');
      } finally {
        setLoading(false);
      }
    };
    fetchEvent();
  }, [id]);

  if (loading) {
    return (
      <Container className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
        <Spinner animation="border" role="status">
          <span className="visually-hidden">Đang tải...</span>
        </Spinner>
      </Container>
    );
  }

  if (error) {
    return (
      <Container className="py-5">
        <Alert variant="danger">{error}</Alert>
        <Button variant="secondary" onClick={() => navigate('/')}>
          Quay lại trang chủ
        </Button>
      </Container>
    );
  }

  if (!event) {
    return (
      <Container className="py-5">
        <Alert variant="warning">Sự kiện không tồn tại.</Alert>
        <Button variant="secondary" onClick={() => navigate('/')}>
          Quay lại trang chủ
        </Button>
      </Container>
    );
  }

  return (
    <Container className="py-5">
      <Row>
        <Col md={8}>
          <Card className="shadow">
            <Card.Body>
              <Card.Title as="h2" className="mb-3">{event.title}</Card.Title>
              <Card.Text className="text-muted mb-3">
                <strong>Địa điểm:</strong> {event.location}
              </Card.Text>
              <Card.Text className="text-muted mb-3">
                <strong>Ngày diễn ra:</strong> {new Date(event.event_date).toLocaleDateString('vi-VN')}
              </Card.Text>
              {event.checkin_start_time && (
                <Card.Text className="text-muted mb-3">
                  <strong>Thời gian check-in:</strong> {event.checkin_start_time} - {event.checkin_end_time}
                </Card.Text>
              )}
              <Card.Text className="mb-4">{event.description}</Card.Text>
              <Button variant="primary" size="lg">
                Mua Vé (Tính năng đang phát triển)
              </Button>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          {event.banner_image && (
            <Card className="shadow">
              <Card.Img variant="top" src={event.banner_image} alt={event.title} />
            </Card>
          )}
        </Col>
      </Row>
      <Row className="mt-4">
        <Col>
          <Button variant="outline-secondary" onClick={() => navigate('/')}>
            Quay lại danh sách sự kiện
          </Button>
        </Col>
      </Row>
    </Container>
  );
};

export default EventDetailPage;
